import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface QuoteData {
  quote: {
    text: string;
    author: string;
    category: string;
  };
}

export default function Widget() {
  const { quote } = response.data as QuoteData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: theme === 'light' ? '#FFFFFF' : '#000000',
        color: theme === 'light' ? '#000000' : '#FFFFFF',
        borderColor: primaryColor,
        borderWidth: 1,
        borderStyle: 'solid',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={1.5}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Quote of the Day
            </Typography>
            <Typography variant="body2" sx={{ mt: 1, mb: 1.5 }}>
              "{quote.text}"
            </Typography>
            <Typography variant="body2" sx={{ fontStyle: 'italic', color: accentColor }}>
              - {quote.author}
            </Typography>
          </Box>
          <Box>
            <Chip
              label={quote.category}
              sx={{
                fontSize: '11px',
                bgcolor: primaryColor,
                color: '#FFFFFF',
                px: 1,
                py: 0.5,
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
